def get_session(info: Info) -> Session:
    return info.context["session"]


@strawberry.type
class Query:
    @strawberry.field
    def products(
        self,
        info: Info,
        seller_id: Optional[int] = None,
        category_id: Optional[int] = None,
        search: Optional[str] = None,
    ) -> List[Product]:
        session = get_session(info)
        stmt = select(ProductModel)

        if seller_id is not None:
            stmt = stmt.where(ProductModel.seller_id == seller_id)

        if category_id is not None:
            stmt = stmt.join(ProductModel.categories).where(CategoryModel.id == category_id)

        if search:
            stmt = stmt.where(ProductModel.name.ilike(f"%{search}%"))

        products = session.execute(stmt).scalars().unique().all()
        return [Product.from_model(product) for product in products]

    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[Product]:
        session = get_session(info)
        product = session.get(ProductModel, id)
        return Product.from_model(product) if product else None

    @strawberry.field
    def sellers(self, info: Info) -> List[Seller]:
        session = get_session(info)
        sellers = session.execute(select(SellerModel)).scalars().all()
        return [Seller.from_model(s) for s in sellers]

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        session = get_session(info)
        categories = session.execute(select(CategoryModel)).scalars().all()
        return [Category.from_model(c) for c in categories]


